'use client'
import { useState, useEffect, useRef } from 'react'
import { supabase } from '@/lib/supabase'
import type { WeddingData, Ucapan } from '../types'

// ── Helpers ──────────────────────────────────────────────────────────
function fmt(iso:string,opts?:Intl.DateTimeFormatOptions){
  if(!iso) return ''
  return new Date(iso).toLocaleDateString('id-ID',opts??{weekday:'long',day:'numeric',month:'long',year:'numeric'})
}
function fmtShort(iso:string){ if(!iso) return ''; return new Date(iso).toLocaleDateString('id-ID',{day:'numeric',month:'long',year:'numeric'}) }
function fmtTime(iso:string){ if(!iso) return ''; return new Date(iso).toLocaleTimeString('id-ID',{hour:'2-digit',minute:'2-digit',hour12:false})+' WIB' }
function parentLabel(n?:string,s?:string){ if(!n) return ''; return (s==='alm'?'Alm. ':s==='almh'?'Almh. ':'')+n }
function useCountdown(target?:string){
  const[t,setT]=useState({d:0,h:0,m:0,s:0,done:false})
  useEffect(()=>{
    if(!target) return
    const tick=()=>{ const diff=new Date(target).getTime()-Date.now(); if(diff<=0){setT({d:0,h:0,m:0,s:0,done:true});return}; setT({d:Math.floor(diff/86400000),h:Math.floor(diff%86400000/3600000),m:Math.floor(diff%3600000/60000),s:Math.floor(diff%60000/1000),done:false}) }
    tick();const id=setInterval(tick,1000);return()=>clearInterval(id)
  },[target])
  return t
}
function gcalUrl(w:WeddingData){
  const tgl=w.resepsi_tanggal||w.akad_tanggal||'';if(!tgl)return '#'
  const st=new Date(tgl),en=new Date(st.getTime()+3*3600000)
  const f=(d:Date)=>d.toISOString().replace(/[-:.]/g,'').slice(0,15)+'Z'
  return `https://calendar.google.com/calendar/render?action=TEMPLATE&text=${encodeURIComponent(`Pernikahan ${w.pria_nama_panggilan} & ${w.wanita_nama_panggilan}`)}&dates=${f(st)}/${f(en)}&location=${encodeURIComponent(w.resepsi_lokasi||'')}` 
}

// ── Assets ───────────────────────────────────────────────────────────
const FL='data:image/png;base64,'
const FR='data:image/png;base64,'
const ILL='data:image/png;base64,'
const ILL2='data:image/png;base64,'
const SW='data:image/png;base64,'
const SG='data:image/png;base64,'

// Palette: maroon-mauve-dusty rose (Jawa Klasik x Floral Tropis)
const C={ maroon:'#7B1C2E', mauve:'#A85070', dusty:'#C4849A', cream:'#FDF8F4', ivoryDark:'#F5EDE4', gold:'#C5A059', text:'#3a2228', muted:'#8a6a72' }

function MahkotaDiv(){ // Javanese crown divider
  return(
    <svg viewBox='0 0 320 24' fill='none' className='w-full max-w-[280px] mx-auto'>
      <line x1='0' y1='12' x2='105' y2='12' stroke='#A85070' strokeWidth='0.6' opacity='0.4'/>
      <path d='M108 12 Q116 4 124 12 Q132 20 140 12' stroke='#A85070' strokeWidth='1.2' fill='none' opacity='0.7'/>
      <path d='M140 12 L146 5 L152 12 L158 5 L164 12 L158 19 L152 12 L146 19 Z' stroke='#A85070' strokeWidth='1' fill='rgba(168,80,112,0.08)' opacity='0.8'/>
      <circle cx='152' cy='12' r='3' fill='#A85070' opacity='0.6'/>
      <path d='M164 12 Q172 4 180 12 Q188 20 196 12' stroke='#A85070' strokeWidth='1.2' fill='none' opacity='0.7'/>
      <line x1='199' y1='12' x2='320' y2='12' stroke='#A85070' strokeWidth='0.6' opacity='0.4'/>
    </svg>
  )
}

function FloralCorner({pos}:{pos:'tl'|'tr'|'bl'|'br'}){
  const src=pos==='tl'||pos==='bl'?FL:FR
  const t={ tl:'top-0 left-0',tr:'top-0 right-0',bl:'bottom-0 left-0',br:'bottom-0 right-0' }[pos]
  const tf={ tl:'translate(-20%,-20%)',tr:'translate(20%,-20%) scaleX(-1)',bl:'translate(-20%,20%) scaleY(-1)',br:'translate(20%,20%) scale(-1)' }[pos]
  return <img src={src} alt='' className={`absolute ${t} pointer-events-none select-none`} style={{width:'clamp(80px,18vw,140px)',opacity:0.65,transform:tf}}/>
}

function SectionHeader({label,title}:{label:string;title:React.ReactNode}){
  return(
    <div className='text-center mb-8'>
      <p style={{fontFamily:"'Cormorant Garamond',serif",fontSize:'0.58rem',letterSpacing:'0.45em',textTransform:'uppercase',color:C.mauve,marginBottom:8}}>{label}</p>
      <h2 style={{fontFamily:"'Cormorant Garamond',serif",fontSize:'clamp(1.8rem,5vw,2.6rem)',color:C.maroon,lineHeight:1.15,fontStyle:'italic',fontWeight:600,margin:'0 0 12px'}}>{title}</h2>
      <MahkotaDiv/>
    </div>
  )
}

// ── COVER ────────────────────────────────────────────────────────────
function Cover({w,onOpen}:{w:WeddingData;onOpen:()=>void}){
  const heroUrl=w.foto_urls?.[0]||''
  const guestName=typeof window!=='undefined'?new URLSearchParams(window.location.search).get('to')||'':''
  return(
    <div id='cover' className='relative w-full' style={{minHeight:'100dvh',background:C.maroon,overflow:'hidden'}}>
      {/* BG foto penuh - kiri */}
      {heroUrl&&(
        <img src={heroUrl} alt='' className='absolute inset-0 w-full h-full object-cover' style={{objectPosition:'center top',opacity:0.85}}/>
      )}
      {/* Gradient overlay maroon dari bawah */}
      <div className='absolute inset-0' style={{background:'linear-gradient(180deg,rgba(60,10,20,0.15) 0%,rgba(60,10,20,0.05) 45%,rgba(60,10,20,0.88) 72%,rgba(60,10,20,0.97) 100%)'}}/>
      {/* Ilustrasi pendopo + bunga di kanan atas — hanya tampil jika tidak ada foto */}
      {!heroUrl&&(
        <img src={ILL} alt='' className='absolute top-0 right-0 w-full h-full object-cover pointer-events-none' style={{opacity:0.25,mixBlendMode:'luminosity'}}/>
      )}
      {/* Floral corner dekorasi */}
      <FloralCorner pos='tl'/><FloralCorner pos='tr'/>
      {/* Info tamu - atas tengah */}
      <div className='absolute top-0 left-0 right-0 z-10 pt-10 text-center px-6'>
        <p style={{fontFamily:"'Cormorant Garamond',serif",fontSize:'0.6rem',letterSpacing:'0.45em',textTransform:'uppercase',color:'rgba(255,255,255,0.5)',marginBottom:4}}>Kepada Yth.</p>
        <p style={{fontFamily:"'Cormorant Garamond',serif",fontSize:'0.82rem',color:'rgba(255,255,255,0.65)',fontStyle:'italic'}}>Bapak / Ibu / Saudara / i</p>
        {guestName&&<p style={{fontFamily:"'Cormorant Garamond',serif",fontSize:'1.15rem',color:'rgba(255,255,255,0.9)',fontWeight:600,marginTop:4}}>{guestName}</p>}
      </div>
      {/* Konten bawah - nama + tanggal + tombol */}
      <div className='absolute bottom-0 left-0 right-0 z-10 px-7 pb-10'>
        <p style={{fontFamily:"'Cormorant Garamond',serif",fontSize:'0.58rem',letterSpacing:'0.55em',textTransform:'uppercase',color:'rgba(255,255,255,0.5)',marginBottom:6}}>Undangan Pernikahan</p>
        <h1 style={{fontFamily:"'Cormorant Garamond',serif",fontStyle:'italic',fontWeight:700,fontSize:'clamp(2.4rem,11vw,4.5rem)',color:'#fff',lineHeight:0.95,letterSpacing:'-0.01em',textShadow:'0 2px 24px rgba(0,0,0,0.5)',marginBottom:4}}>
          {w.pria_nama_panggilan||'Nama Pria'}
        </h1>
        <p style={{fontFamily:"'Cormorant Garamond',serif",fontStyle:'italic',fontSize:'clamp(1.3rem,5vw,2rem)',color:'rgba(197,160,89,0.9)',marginBottom:4}}>&amp;</p>
        <h1 style={{fontFamily:"'Cormorant Garamond',serif",fontStyle:'italic',fontWeight:700,fontSize:'clamp(2.4rem,11vw,4.5rem)',color:'#fff',lineHeight:0.95,letterSpacing:'-0.01em',textShadow:'0 2px 24px rgba(0,0,0,0.5)',marginBottom:10}}>
          {w.wanita_nama_panggilan||'Nama Wanita'}
        </h1>
        <div style={{width:36,height:1,background:'linear-gradient(to right,transparent,rgba(197,160,89,0.8),transparent)',marginBottom:8}}/>
        {w.resepsi_tanggal&&<p style={{fontFamily:"'Cormorant Garamond',serif",fontSize:'0.75rem',letterSpacing:'0.25em',textTransform:'uppercase',color:'rgba(255,255,255,0.5)',marginBottom:22}}>{fmtShort(w.resepsi_tanggal)}</p>}
        <button onClick={onOpen} className='transition-all active:scale-95'
          style={{fontFamily:"'Cormorant Garamond',serif",fontStyle:'italic',fontSize:'0.85rem',letterSpacing:'0.2em',
            padding:'13px 36px',borderRadius:4,
            background:C.mauve,color:'#fff',border:'none',cursor:'pointer',
            boxShadow:'0 4px 20px rgba(123,28,46,0.4)'}}>
          Buka Undangan
        </button>
      </div>
    </div>
  )
}

