function SectionQuote({w}:{w:WeddingData}){
  const pilihan = w.kata_kata_pilihan || 'quran'
  const isQuran  = pilihan === 'quran'
  const isBible  = pilihan === 'bible'
  const isCustom = pilihan === 'custom'

  const preset = isQuran ? KATA_QURAN : KATA_BIBLE

  return(
    <section className='relative overflow-hidden' style={{background:C.cream}}>
      <FloralCorner pos='tl'/><FloralCorner pos='tr'/>
      <div className='relative z-10 px-6 py-16 text-center' style={{maxWidth:580,margin:'0 auto'}}>
        {isCustom ? (
          <>
            <SectionHeader label='Kata-kata' title={<em>Untuk Kamu</em>}/>
            <blockquote style={{fontFamily:"'Cormorant Garamond',serif",fontStyle:'italic',fontSize:'clamp(0.95rem,2.5vw,1.15rem)',color:C.text,lineHeight:2,maxWidth:480,margin:'0 auto 20px'}}>
              &#34;{w.kata_kata_custom || 'Kata-kata indah untuk undangan ini...'}&#34;
            </blockquote>
          </>
        ) : (
          <>
            <SectionHeader label={preset.label} title={preset.title}/>
            <blockquote style={{fontFamily:"'Cormorant Garamond',serif",fontStyle:'italic',fontSize:'clamp(0.95rem,2.5vw,1.15rem)',color:C.text,lineHeight:2,maxWidth:480,margin:'0 auto 16px'}}>
              {preset.text}
            </blockquote>
            <cite style={{fontFamily:"'Cormorant Garamond',serif",fontSize:'0.65rem',letterSpacing:'0.35em',textTransform:'uppercase',color:C.mauve,fontStyle:'normal',display:'block',marginBottom:20}}>
              {preset.source}
            </cite>
            <p style={{fontFamily:"'Lato',sans-serif",fontSize:'0.82rem',color:C.muted,lineHeight:1.9,maxWidth:420,margin:'0 auto'}}>
              {preset.sub}
            </p>
          </>
        )}
      </div>
    </section>
  )
}

function SectionMempelai({w}:{w:WeddingData}){
  const Card=({type}:{type:'pria'|'wanita'})=>{
    const p=type==='pria'
    const foto=p?(w.pria_foto_url||w.foto_urls?.[1]):(w.wanita_foto_url||w.foto_urls?.[2])
    const nama=p?(w.pria_nama_lengkap||w.pria_nama_panggilan):(w.wanita_nama_lengkap||w.wanita_nama_panggilan)
    const gelar=p?w.pria_gelar:w.wanita_gelar
    const ayah=parentLabel(p?w.pria_nama_ayah:w.wanita_nama_ayah,p?w.pria_status_ayah:w.wanita_status_ayah)
    const ibu=parentLabel(p?w.pria_nama_ibu:w.wanita_nama_ibu,p?w.pria_status_ibu:w.wanita_status_ibu)
    return(
      <div className='text-center'>
        <p style={{fontFamily:"'Cormorant Garamond',serif",fontSize:'0.55rem',letterSpacing:'0.4em',textTransform:'uppercase',color:C.dusty,marginBottom:12}}>{p?'The Groom':'The Bride'}</p>
        {/* Photo frame dengan border maroon */}
        <div className='relative mx-auto mb-5' style={{width:150,height:150}}>
          <div style={{position:'absolute',inset:'-6px',border:`2px solid rgba(168,80,112,0.3)`,borderRadius:'50%'}}/>
          <div className='w-full h-full rounded-full overflow-hidden' style={{border:`2.5px solid ${C.mauve}`,boxShadow:`0 8px 32px rgba(123,28,46,0.2)`}}>
            {foto?<img src={foto} alt={nama||''} className='w-full h-full object-cover' style={{objectPosition:'center top'}}/>
                 :<div className='w-full h-full flex items-center justify-center text-5xl' style={{background:`linear-gradient(135deg,${C.cream},${C.ivoryDark})`}}>{p?'🤵':'👰'}</div>}
          </div>
          <img src={p?SG:SW} alt='' className='absolute inset-0 w-full h-full pointer-events-none' style={{opacity:0.35}}/>
        </div>
        <h3 style={{fontFamily:"'Cormorant Garamond',serif",fontStyle:'italic',fontSize:'1.25rem',color:C.maroon,fontWeight:600,marginBottom:4,lineHeight:1.3}}>
          {gelar?`${gelar} `:''}{nama}
        </h3>
        {(ayah||ibu)&&<p className='text-xs leading-loose mt-1' style={{fontFamily:"'Lato',sans-serif",color:C.muted}}>
          {p?'Putra':'Putri'} dari<br/>
          <span style={{color:C.mauve,fontWeight:600}}>{ayah}</span>
          {ibu&&<><br/>&amp; <span style={{color:C.mauve,fontWeight:600}}>{ibu}</span></>}
        </p>}
      </div>
    )
  }
  return(
    <section id='mempelai' className='relative overflow-hidden' style={{background:C.ivoryDark}}>
      <FloralCorner pos='bl'/><FloralCorner pos='br'/>
      <div className='relative z-10 px-5 py-16 text-center' style={{maxWidth:580,margin:'0 auto'}}>
        <SectionHeader label='Mempelai' title={<>Yang Akan <em>Dipersatukan</em></>}/>
        <div style={{display:'grid',gridTemplateColumns:'1fr auto 1fr',gap:'28px 16px',alignItems:'start'}}>
          <Card type='pria'/>
          <div className='flex flex-col items-center' style={{paddingTop:32}}>
            <div style={{width:1,height:32,background:`linear-gradient(to bottom,transparent,${C.mauve})`}}/>
            <span style={{fontFamily:"'Cormorant Garamond',serif",fontStyle:'italic',fontSize:'1.7rem',color:C.mauve,padding:'4px 0'}}>&amp;</span>
            <div style={{width:1,height:32,background:`linear-gradient(to top,transparent,${C.mauve})`}}/>
          </div>
          <Card type='wanita'/>
        </div>
      </div>
    </section>
  )
}

function SectionAcara({w}:{w:WeddingData}){
  const target=w.resepsi_tanggal||w.akad_tanggal||''
  const{d,h,m,s,done}=useCountdown(target)
  const EvCard=({type}:{type:'akad'|'resepsi'})=>{
    const isA=type==='akad'
    const tgl=isA?w.akad_tanggal:w.resepsi_tanggal;if(!tgl)return null
    const lok=isA?w.akad_lokasi:w.resepsi_lokasi
    const adr=isA?w.akad_alamat:w.resepsi_alamat
    const mp=isA?w.akad_maps_url:w.resepsi_maps_url
    return(
      <div className='rounded-2xl overflow-hidden' style={{background:'#fff',border:`1px solid rgba(168,80,112,0.15)`,boxShadow:'0 4px 20px rgba(123,28,46,0.08)'}}>
        <div style={{height:3,background:`linear-gradient(to right,${C.cream},${C.mauve},${C.cream})`}}/>
        <div className='p-5 text-center'>
          <span style={{fontFamily:"'Cormorant Garamond',serif",fontSize:'0.55rem',letterSpacing:'0.4em',textTransform:'uppercase',color:C.dusty,display:'block',marginBottom:4}}>{isA?'01':'02'}</span>
          <h3 style={{fontFamily:"'Cormorant Garamond',serif",fontStyle:'italic',fontWeight:600,fontSize:'1.1rem',color:C.maroon,marginBottom:10}}>{isA?'Akad Nikah':'Resepsi Pernikahan'}</h3>
          <MahkotaDiv/>
          <div className='space-y-2 text-left mt-4'>
            <div className='flex gap-2 items-start text-xs' style={{fontFamily:"'Lato',sans-serif",color:C.muted}}><span>📅</span><span className='leading-relaxed'>{fmt(tgl)}</span></div>
            <div className='flex gap-2 items-start text-xs' style={{fontFamily:"'Lato',sans-serif",color:C.muted}}><span>⏰</span><span>{fmtTime(tgl)}</span></div>
            {lok&&<div className='flex gap-2 items-start text-xs' style={{fontFamily:"'Lato',sans-serif",color:C.muted}}><span className='flex-shrink-0'>📍</span><span className='leading-relaxed'>{lok}{adr?` · ${adr}`:''}</span></div>}
          </div>
          {mp&&<a href={mp} target='_blank' rel='noopener noreferrer' className='inline-flex items-center gap-1.5 mt-4 transition-all active:scale-95' style={{fontFamily:"'Lato',sans-serif",fontSize:'0.62rem',letterSpacing:'0.08em',padding:'9px 20px',borderRadius:4,background:C.mauve,color:'#fff',textDecoration:'none'}}>📍 Lihat Lokasi</a>}
        </div>
      </div>
    )
  }
  return(
    <section id='acara' className='relative overflow-hidden' style={{background:C.cream}}>
      <FloralCorner pos='tl'/><FloralCorner pos='br'/>
      <div className='relative z-10 px-5 py-16 text-center' style={{maxWidth:580,margin:'0 auto'}}>
        <SectionHeader label='Save the Date' title={<>Hari <em>Bahagia</em> Kami</>}/>
        {target&&<p className='text-sm mb-6' style={{fontFamily:"'Lato',sans-serif",color:C.muted,marginTop:-16}}>{fmt(target)}</p>}
        {!done?(
          <div className='flex justify-center gap-2.5 mb-10'>
            {(['d','h','m','s'] as const).map(k=>{
              const val=k==='d'?d:k==='h'?h:k==='m'?m:s
              const lbl=k==='d'?'Hari':k==='h'?'Jam':k==='m'?'Menit':'Detik'
              return(
                <div key={k} className='flex flex-col items-center rounded-xl' style={{background:'#fff',border:`1px solid rgba(168,80,112,0.2)`,boxShadow:'0 4px 16px rgba(123,28,46,0.08)',width:68,paddingTop:14,paddingBottom:14}}>
                  <span style={{fontFamily:"'Cormorant Garamond',serif",fontSize:'1.9rem',fontWeight:700,color:C.maroon,lineHeight:1}}>{String(val).padStart(2,'0')}</span>
                  <span style={{fontFamily:"'Lato',sans-serif",fontSize:'0.5rem',letterSpacing:'0.3em',textTransform:'uppercase',color:C.dusty,marginTop:5}}>{lbl}</span>
                </div>
              )
            })}
          </div>
        ):<p style={{fontFamily:"'Cormorant Garamond',serif",fontStyle:'italic',fontSize:'1.3rem',color:C.mauve,margin:'24px 0'}}>🎉 Hari Bahagia Telah Tiba!</p>}
        <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(230px,1fr))',gap:14,marginBottom:20}}>
          <EvCard type='akad'/><EvCard type='resepsi'/>
        </div>
        {target&&<a href={gcalUrl(w)} target='_blank' rel='noopener noreferrer' className='inline-flex items-center gap-2 transition-all active:scale-95 mt-2' style={{fontFamily:"'Lato',sans-serif",fontSize:'0.62rem',letterSpacing:'0.08em',padding:'10px 22px',borderRadius:4,border:`1.5px solid ${C.mauve}`,color:C.mauve,background:'transparent',textDecoration:'none'}}>📅 Tambah ke Kalender</a>}
      </div>
    </section>
  )
}

function SectionRSVP({w}:{w:WeddingData}){
  const[form,setForm]=useState({nama:'',ucapan:'',hadir:'hadir'})
  const[busy,setBusy]=useState(false);const[ok,setOk]=useState(false)
  const[list,setList]=useState<Ucapan[]>([]);const[loading,setLoading]=useState(true)
  useEffect(()=>{ supabase.from('ucapan').select('*').eq('order_id',w.order_id).order('created_at',{ascending:false}).limit(30).then(({data})=>{if(data)setList(data as Ucapan[]);setLoading(false)}) },[w.order_id])
  async function send(){
    if(!form.nama.trim()||!form.ucapan.trim()) return
    setBusy(true)
    const{data}=await supabase.from('ucapan').insert({order_id:w.order_id,...form}).select().single()
    if(data)setList(p=>[data as Ucapan,...p])
    setOk(true);setBusy(false);setForm({nama:'',ucapan:'',hadir:'hadir'})
    setTimeout(()=>setOk(false),3000)
  }
  const iS:React.CSSProperties={width:'100%',padding:'12px 16px',border:`1.5px solid rgba(168,80,112,0.2)`,borderRadius:6,fontFamily:"'Lato',sans-serif",fontSize:'0.82rem',color:C.text,background:'#fff',outline:'none',boxSizing:'border-box'}
  return(
    <section id='rsvp' className='relative overflow-hidden' style={{background:C.ivoryDark}}>
      <FloralCorner pos='tr'/><FloralCorner pos='bl'/>
      <div className='relative z-10 px-5 py-16 text-center' style={{maxWidth:520,margin:'0 auto'}}>
        <SectionHeader label='Konfirmasi Kehadiran' title={<>RSVP &amp; <em>Buku Tamu</em></>}/>
        <p className='text-sm leading-loose mb-6 mx-auto' style={{fontFamily:"'Lato',sans-serif",color:C.muted,maxWidth:360,marginTop:-16}}>Kehormatan kami apabila Bapak/Ibu/Saudara/i berkenan hadir memberikan doa restu.</p>
        {!ok?(
          <div className='text-left space-y-4'>
            <div><label style={{fontFamily:"'Lato',sans-serif",fontSize:'0.6rem',letterSpacing:'0.2em',textTransform:'uppercase',color:C.dusty,display:'block',marginBottom:7}}>Nama</label><input value={form.nama} onChange={e=>setForm(f=>({...f,nama:e.target.value}))} placeholder='Nama lengkap Anda' style={iS}/></div>
            <div><label style={{fontFamily:"'Lato',sans-serif",fontSize:'0.6rem',letterSpacing:'0.2em',textTransform:'uppercase',color:C.dusty,display:'block',marginBottom:7}}>Kehadiran</label>
            <div className='flex gap-2'>{[['hadir','✅ Hadir'],['tidak','❌ Tidak'],['ragu','🤔 Mungkin']].map(([v,l])=>(
              <button key={v} onClick={()=>setForm(f=>({...f,hadir:v}))} className='flex-1 transition-all active:scale-95'
                style={{fontFamily:"'Lato',sans-serif",fontSize:'0.7rem',padding:'10px 4px',borderRadius:6,border:`1.5px solid ${form.hadir===v?C.mauve:'rgba(168,80,112,0.2)'}`,background:form.hadir===v?`rgba(168,80,112,0.08)`:'#fff',color:form.hadir===v?C.mauve:C.muted,cursor:'pointer',fontWeight:form.hadir===v?700:400}}>{l}</button>
            ))}</div></div>
            <div><label style={{fontFamily:"'Lato',sans-serif",fontSize:'0.6rem',letterSpacing:'0.2em',textTransform:'uppercase',color:C.dusty,display:'block',marginBottom:7}}>Ucapan &amp; Doa</label><textarea value={form.ucapan} onChange={e=>setForm(f=>({...f,ucapan:e.target.value}))} placeholder='Tulis ucapan terbaikmu...' rows={3} style={{...iS,resize:'none'}}/></div>
            <button onClick={send} disabled={busy||!form.nama||!form.ucapan} className='w-full transition-all active:scale-95 disabled:opacity-50'
              style={{fontFamily:"'Lato',sans-serif",fontWeight:700,fontSize:'0.72rem',letterSpacing:'0.18em',textTransform:'uppercase',padding:'14px',borderRadius:4,background:C.mauve,color:'#fff',border:'none',cursor:'pointer',boxShadow:`0 6px 20px rgba(123,28,46,0.25)`}}>
              {busy?'Mengirim...':'Kirim Ucapan 💌'}
            </button>
          </div>
        ):<div className='py-8 rounded-2xl' style={{background:`rgba(168,80,112,0.06)`,border:`1px solid rgba(168,80,112,0.2)`}}><p style={{fontFamily:"'Cormorant Garamond',serif",fontStyle:'italic',fontSize:'1rem',color:C.mauve}}>Terima kasih atas ucapan dan doamu! 🌸</p></div>}
        <div className='mt-8'>
          <p style={{fontFamily:"'Cormorant Garamond',serif",fontStyle:'italic',fontSize:'0.85rem',color:C.dusty,marginBottom:12}}>— Ucapan &amp; Doa —</p>
          <div className='space-y-3 text-left' style={{maxHeight:300,overflowY:'auto'}}>
            {loading?<p className='text-center text-sm py-4' style={{color:`rgba(168,80,112,0.5)`}}>Memuat...</p>
            :list.length===0?<p className='text-center text-sm py-4' style={{color:`rgba(168,80,112,0.5)`}}>Jadilah yang pertama memberi ucapan 💕</p>
            :list.map(u=>(<div key={u.id} className='rounded-xl px-4 py-3' style={{background:'#fff',borderLeft:`3px solid rgba(168,80,112,0.4)`,border:`1px solid rgba(168,80,112,0.1)`}}>
              <div className='flex justify-between mb-1'><p style={{fontFamily:"'Lato',sans-serif",fontWeight:700,fontSize:'0.78rem',color:C.mauve}}>{u.nama}</p><span>{u.hadir==='hadir'?'✅':u.hadir==='tidak'?'❌':'🤔'}</span></div>
              <p style={{fontFamily:"'Lato',sans-serif",fontSize:'0.76rem',color:C.muted,lineHeight:1.65}}>{u.ucapan}</p>
            </div>))}
          </div>
        </div>
      </div>
    </section>
  )
}

function SectionGallery({w}:{w:WeddingData}){
  const fotos=w.foto_urls||[];const[lb,setLb]=useState<number|null>(null)
  if(!fotos.length)return null
  return(
    <section id='galeri' className='relative overflow-hidden' style={{background:C.cream}}>
      <FloralCorner pos='tl'/><FloralCorner pos='br'/>
      <div className='relative z-10 py-16' style={{maxWidth:580,margin:'0 auto'}}>
        <div className='px-5 text-center mb-6'><SectionHeader label='Galeri Foto' title={<>Momen <em>Berharga</em></>}/></div>
        <div className='px-3 columns-2 gap-2'>
          {fotos.map((url,i)=>(<div key={url} className='break-inside-avoid mb-2 cursor-pointer group' onClick={()=>setLb(i)}>
            <div className='overflow-hidden rounded-xl relative'>
              <img src={url} alt='' loading='lazy' className='w-full object-cover transition-transform duration-500 group-active:scale-105' style={{aspectRatio:i%4===0?'3/4':i%4===1?'1/1':i%4===2?'4/5':'1/1',display:'block'}}/>
              <div className='absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center' style={{background:`rgba(123,28,46,0.18)`}}>
                <span style={{fontSize:'1.3rem'}}>🔍</span></div></div></div>))}
        </div>
      </div>
      {lb!==null&&(<div className='fixed inset-0 z-50 flex items-center justify-center' style={{background:'rgba(0,0,0,0.95)'}} onClick={()=>setLb(null)}>
        <button className='absolute top-4 right-5 text-white text-3xl p-2 z-10' onClick={()=>setLb(null)}>×</button>
        <button className='absolute left-2 text-white text-5xl p-4 z-10' onClick={e=>{e.stopPropagation();setLb(l=>l!>0?l!-1:fotos.length-1)}}>&#8249;</button>
        <img src={fotos[lb]} alt='' className='max-h-[82dvh] max-w-[94vw] rounded-xl object-contain' onClick={e=>e.stopPropagation()}/>
        <button className='absolute right-2 text-white text-5xl p-4 z-10' onClick={e=>{e.stopPropagation();setLb(l=>l!<fotos.length-1?l!+1:0)}}>&#8250;</button>
        <p className='absolute bottom-5 text-sm' style={{color:'rgba(255,255,255,0.4)'}}>{lb+1} / {fotos.length}</p>
      </div>)}
    </section>
  )
}

