// ── Invite Navbar (fixed-top, white → transparent on scroll) ─────────
// ── Navbar ────────────────────────────────────────────────────────────
// Fixed di atas kolom kanan. Scroll dari #jf-scroll:
//   - Di atas (y<40)       → bg putih, logo hijau
//   - Scroll ke bawah      → sembunyikan (translateY -100%)
//   - Scroll ke atas lagi  → muncul, bg transparan, logo putih
function JFNavbar({opened}:{opened:boolean}){
  const[show,setShow]=useState(true)
  const[atTop,setAtTop]=useState(true)
  const lastY=useRef(0)

  useEffect(()=>{
    let sc:HTMLElement|null=null

    function getY(){ return sc ? sc.scrollTop : window.scrollY }

    function onScroll(){
      const y=getY()
      const goingDown=y>lastY.current+3
      const goingUp=y<lastY.current-3
      lastY.current=y
      setAtTop(y<50)
      if(y<50)      setShow(true)
      else if(goingDown) setShow(false)
      else if(goingUp)   setShow(true)
    }

    function attach(){
      sc=document.getElementById('jf-scroll')
      if(sc) sc.addEventListener('scroll',onScroll,{passive:true})
      window.addEventListener('scroll',onScroll,{passive:true})
      onScroll()
    }
    attach()
    const t=setTimeout(attach,300)
    return()=>{
      clearTimeout(t)
      if(sc) sc.removeEventListener('scroll',onScroll)
      window.removeEventListener('scroll',onScroll)
    }
  },[opened])

  // Logika warna:
  // - Cover (belum dibuka) & di atas → transparan, logo putih (di atas foto gelap)
  // - Desktop di atas → transparan juga (kiri = slideshow foto gelap)
  // - Sudah scroll / scroll ke atas → bg putih + shadow, logo hijau
  const isTransparent = atTop && (!opened)
  const bgColor  = isTransparent ? 'transparent' : 'rgba(255,255,255,0.97)'
  const shadow   = isTransparent ? 'none' : '0 1px 12px rgba(0,0,0,0.09)'
  const logoFilter = isTransparent
    ? 'brightness(0) invert(1)'
    : 'brightness(0) saturate(100%) invert(22%) sepia(55%) saturate(600%) hue-rotate(128deg)'

  return(
    <>
      <style>{`
        #jf-topnav{
          position:fixed;
          top:0; left:0; right:0;
          width:100vw;
          z-index:200;
          height:50px;
          display:flex;
          align-items:center;
          justify-content:center;
          pointer-events:none;
          will-change:transform,background;
          transition:transform 0.28s ease, background 0.28s ease, box-shadow 0.28s ease;
        }
        @media(min-width:768px){
          #jf-topnav{
            left:0 !important;
            width:100vw !important;
            right:0 !important;
          }
        }
      `}</style>
      <div id='jf-topnav' style={{
        transform: show ? 'translateY(0)' : 'translateY(-110%)',
        background: bgColor,
        boxShadow: shadow,
      }}>
        <img
          src='/logo_light.svg'
          alt='Katresnan'
          style={{
            height:26, width:'auto', display:'block',
            transition:'filter 0.28s ease',
            filter: logoFilter,
          }}
        />
      </div>
    </>
  )
}

// ── Desktop Slideshow ─────────────────────────────────────────────────
function DesktopSlideshow({w}:{w:WeddingData}){
  const fotos=(w.foto_urls||[]).filter(Boolean)
  const[cur,setCur]=useState(0)
  const[fade,setFade]=useState(true)
  useEffect(()=>{
    if(fotos.length<2)return
    const id=setInterval(()=>{
      setFade(false)
      setTimeout(()=>{setCur(c=>(c+1)%fotos.length);setFade(true)},350)
    },4500)
    return()=>clearInterval(id)
  },[fotos.length])
  function goTo(i:number){setFade(false);setTimeout(()=>{setCur(i);setFade(true)},300)}
  function prev(){goTo((cur-1+fotos.length)%fotos.length)}
  function next(){goTo((cur+1)%fotos.length)}
  if(!fotos.length)return(
    <div className='w-full h-full flex items-center justify-center' style={{background:`linear-gradient(135deg,${C.maroon},#3a0e1a)`}}>
      <img src={ILL} alt='' style={{width:'70%',maxWidth:400,opacity:0.25,mixBlendMode:'luminosity'}}/>
    </div>
  )
  return(
    <div className='relative w-full h-full overflow-hidden' style={{background:'#1a0a0e'}}>
      <img key={cur} src={fotos[cur]} alt='' className='absolute inset-0 w-full h-full object-cover'
        style={{objectPosition:'center top',opacity:fade?0.9:0,transition:'opacity 0.4s ease'}}/>
      <div className='absolute inset-0' style={{background:'linear-gradient(180deg,rgba(26,8,14,0.2) 0%,rgba(26,8,14,0.0) 35%,rgba(26,8,14,0.65) 100%)'}}/>
      <img src={FL} alt='' className='absolute top-0 left-0 pointer-events-none' style={{width:200,opacity:0.6,transform:'translate(-22%,-22%)'}}/>
      <img src={FR} alt='' className='absolute top-0 right-0 pointer-events-none' style={{width:200,opacity:0.6,transform:'translate(22%,-22%) scaleX(-1)'}}/>
      <img src={FL} alt='' className='absolute bottom-0 left-0 pointer-events-none' style={{width:160,opacity:0.35,transform:'translate(-22%,22%) scaleY(-1)'}}/>
      <img src={FR} alt='' className='absolute bottom-0 right-0 pointer-events-none' style={{width:160,opacity:0.35,transform:'translate(22%,22%) scale(-1)'}}/>
      <div className='absolute bottom-0 left-0 right-0 px-12 pb-12 z-10'>
        <p style={{fontFamily:"'Cormorant Garamond',serif",fontSize:'0.58rem',letterSpacing:'0.55em',textTransform:'uppercase',color:'rgba(255,255,255,0.42)',marginBottom:8}}>Undangan Pernikahan</p>
        <h2 style={{fontFamily:"'Cormorant Garamond',serif",fontStyle:'italic',fontWeight:700,fontSize:'clamp(2.4rem,3.8vw,3.8rem)',color:'#fff',lineHeight:0.95,textShadow:'0 2px 24px rgba(0,0,0,0.55)',margin:'0 0 4px'}}>
          {w.pria_nama_panggilan||'Nama Pria'}
        </h2>
        <p style={{fontFamily:"'Cormorant Garamond',serif",fontStyle:'italic',fontSize:'clamp(1.4rem,2.2vw,2rem)',color:'rgba(197,160,89,0.85)',lineHeight:1,margin:'4px 0'}}>&amp;</p>
        <h2 style={{fontFamily:"'Cormorant Garamond',serif",fontStyle:'italic',fontWeight:700,fontSize:'clamp(2.4rem,3.8vw,3.8rem)',color:'#fff',lineHeight:0.95,textShadow:'0 2px 24px rgba(0,0,0,0.55)',margin:'4px 0 12px'}}>
          {w.wanita_nama_panggilan||'Nama Wanita'}
        </h2>
        <div style={{width:40,height:1,background:'linear-gradient(to right,transparent,rgba(197,160,89,0.7),transparent)',marginBottom:10}}/>
        {w.resepsi_tanggal&&<p style={{fontFamily:"'Cormorant Garamond',serif",fontSize:'0.7rem',letterSpacing:'0.3em',textTransform:'uppercase',color:'rgba(255,255,255,0.42)'}}>{fmtShort(w.resepsi_tanggal)}</p>}
      </div>
      {fotos.length>1&&(
        <>
          <button onClick={prev} className='absolute left-5 top-1/2 -translate-y-1/2 z-20 flex items-center justify-center transition-all hover:scale-110 active:scale-90'
            style={{width:42,height:42,borderRadius:'50%',background:'rgba(0,0,0,0.3)',border:'1px solid rgba(255,255,255,0.18)',color:'#fff',fontSize:'1.4rem',cursor:'pointer',backdropFilter:'blur(8px)'}}>&#8249;</button>
          <button onClick={next} className='absolute right-5 top-1/2 -translate-y-1/2 z-20 flex items-center justify-center transition-all hover:scale-110 active:scale-90'
            style={{width:42,height:42,borderRadius:'50%',background:'rgba(0,0,0,0.3)',border:'1px solid rgba(255,255,255,0.18)',color:'#fff',fontSize:'1.4rem',cursor:'pointer',backdropFilter:'blur(8px)'}}>&#8250;</button>
          <div className='absolute bottom-8 left-1/2 -translate-x-1/2 z-20 flex gap-2 items-center'>
            {fotos.map((_,i)=>(
              <button key={i} onClick={()=>goTo(i)} style={{width:i===cur?24:7,height:7,borderRadius:4,background:i===cur?'rgba(197,160,89,0.95)':'rgba(255,255,255,0.3)',border:'none',cursor:'pointer',transition:'all 0.3s ease',padding:0}}/>
            ))}
          </div>
          <div className='absolute top-7 right-8 z-20'>
            <span style={{fontFamily:"'Lato',sans-serif",fontSize:'0.58rem',letterSpacing:'0.18em',color:'rgba(255,255,255,0.38)'}}>{String(cur+1).padStart(2,'0')} / {String(fotos.length).padStart(2,'0')}</span>
          </div>
        </>
      )}
    </div>
  )
}

// ── ROOT ──────────────────────────────────────────────────────────────
export default function TemplateJogjaFloral({wedding:wd}:{wedding:WeddingData}){
  const[opened,setOpened]=useState(false)
  const[playing,setPlaying]=useState(false)
  const audioRef=useRef<HTMLAudioElement|null>(null)
  function open(){
    setOpened(true)
    audioRef.current?.play().then(()=>setPlaying(true)).catch(()=>{})
    const sc=document.getElementById('jf-scroll')
    if(sc)sc.scrollTop=0
  }
  function toggleMusic(){
    if(!audioRef.current)return
    if(playing){audioRef.current.pause();setPlaying(false)}
    else{audioRef.current.play().then(()=>setPlaying(true)).catch(()=>{})}
  }
  return(
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,400;0,600;0,700;1,400;1,600;1,700&family=Lato:wght@300;400;700&display=swap');
        *,*::before,*::after{box-sizing:border-box;-webkit-tap-highlight-color:transparent;-webkit-font-smoothing:antialiased;}
        html{font-size:16px;scroll-behavior:smooth;}

        /* ══ MOBILE ══ */
        body{margin:0;padding:0;background:${C.cream};overflow-x:hidden;}
        .jf-left{display:none;}
        .jf-right{width:100%;min-height:100dvh;background:${C.cream};}
        .jf-root{width:100%;overflow-x:hidden;padding-bottom:64px;background:${C.cream};}

        /* ══ DESKTOP ≥768px ══ */
        @media(min-width:768px){
          html,body{height:100%;overflow:hidden;background:#1a0a0e;}

          /* Kiri: fixed, 66.67vw, full tinggi */
          .jf-left{
            display:block;
            position:fixed;
            top:0; left:0;
            width:66.667vw;
            height:100vh;
            z-index:1;
          }

          /* Kanan: fixed, mulai dari 66.667vw, sisa lebar, scroll mandiri */
          .jf-right{
            position:fixed;
            top:0;
            left:66.667vw;
            width:33.333vw;
            height:100vh;
            overflow-y:auto;
            overflow-x:hidden;
            z-index:2;
            background:${C.cream};
            box-shadow:-4px 0 24px rgba(0,0,0,0.25);
            scrollbar-width:thin;
            scrollbar-color:rgba(168,80,112,0.2) transparent;
          }
          .jf-right::-webkit-scrollbar{width:3px;}
          .jf-right::-webkit-scrollbar-thumb{background:rgba(168,80,112,0.2);border-radius:2px;}

          .jf-root{min-height:100vh;padding-bottom:72px;}

          /* BottomNav: snap ke kolom kanan */
          #jf-nav{
            left:66.667vw !important;
            width:33.333vw !important;
            right:unset !important;
          }

          /* Musik btn: pojok kanan atas di dalam kolom kanan */
          #jf-music{
            right:16px !important;
          }
        }

        @keyframes jfFadeUp{from{opacity:0;transform:translateY(14px);}to{opacity:1;transform:none;}}
        .jf-section{animation:jfFadeUp 0.5s ease both;}
        input:focus,textarea:focus{border-color:rgba(168,80,112,0.5)!important;box-shadow:0 0 0 3px rgba(168,80,112,0.08)!important;outline:none!important;}
        ::-webkit-scrollbar{width:3px;}
        ::-webkit-scrollbar-thumb{background:rgba(168,80,112,0.2);border-radius:2px;}
      `}</style>

      <audio ref={audioRef} loop preload='none'>
        {wd.musik_pilihan?.startsWith('http')&&<source src={wd.musik_pilihan}/>}
      </audio>

      {/* Navbar — fixed, snap ke kolom kanan di desktop */}
      <JFNavbar opened={opened}/>

      {/* Kiri: Slideshow prewedding — desktop only */}
      <div className='jf-left'>
        <DesktopSlideshow w={wd}/>
      </div>

      {/* Kanan: Undangan */}
      <div className='jf-right' id='jf-scroll'>
        <div className='jf-root'>
          {!opened
            ?<Cover w={wd} onOpen={open}/>
            :<main>
                <div className='jf-section'><SectionQuote w={wd}/></div>
                <div className='jf-section'><SectionMempelai w={wd}/></div>
                <div className='jf-section'><SectionAcara w={wd}/></div>
                <div className='jf-section'><SectionRSVP w={wd}/></div>
                <div className='jf-section'><SectionGallery w={wd}/></div>
                <div className='jf-section'><SectionLoveStory w={wd}/></div>
                <div className='jf-section'><SectionGift w={wd}/></div>
                <div className='jf-section'><SectionFooter w={wd}/></div>
              </main>
          }
        </div>
      </div>

      {/* Musik btn */}
      {opened&&(
        <button id='jf-music' onClick={toggleMusic}
          className='fixed top-4 right-4 z-50 flex items-center justify-center rounded-full transition-all active:scale-90'
          style={{width:42,height:42,background:playing?C.mauve:'rgba(253,248,244,0.96)',border:`1.5px solid rgba(168,80,112,0.3)`,color:playing?'#fff':C.mauve,cursor:'pointer',backdropFilter:'blur(12px)',boxShadow:'0 3px 14px rgba(123,28,46,0.18)',fontSize:'1rem'}}>
          {playing?'♪':'♩'}
        </button>
      )}

      {/* BottomNav */}
      {opened&&<BottomNavFixed w={wd}/>}
    </>
  )
}

function BottomNavFixed({w}:{w:WeddingData}){
  const[active,setActive]=useState('cover')
  const items=[
    {id:'cover',    label:'Home',     icon:<svg viewBox='0 0 24 24' fill='none' stroke='currentColor' strokeWidth='1.8' width='20' height='20'><path d='M3 12L12 4l9 8'/><path d='M5 10v9a1 1 0 001 1h4v-5h4v5h4a1 1 0 001-1v-9'/></svg>},
    {id:'mempelai', label:'Mempelai', icon:<svg viewBox='0 0 24 24' fill='none' stroke='currentColor' strokeWidth='1.8' width='20' height='20'><circle cx='9' cy='7' r='4'/><path d='M3 21v-2a4 4 0 014-4h4'/><path d='M19 21v-2a4 4 0 00-4-4h-1'/><circle cx='19' cy='8' r='3'/></svg>},
    {id:'acara',    label:'Acara',    icon:<svg viewBox='0 0 24 24' fill='none' stroke='currentColor' strokeWidth='1.8' width='20' height='20'><rect x='3' y='4' width='18' height='18' rx='2'/><line x1='16' y1='2' x2='16' y2='6'/><line x1='8' y1='2' x2='8' y2='6'/><line x1='3' y1='10' x2='21' y2='10'/></svg>},
    {id:'rsvp',     label:'RSVP',     icon:<svg viewBox='0 0 24 24' fill='none' stroke='currentColor' strokeWidth='1.8' width='20' height='20'><path d='M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z'/></svg>},
    {id:'galeri',   label:'Galeri',   icon:<svg viewBox='0 0 24 24' fill='none' stroke='currentColor' strokeWidth='1.8' width='20' height='20'><rect x='3' y='3' width='18' height='18' rx='2'/><circle cx='8.5' cy='8.5' r='1.5'/><path d='M21 15l-5-5L5 21'/></svg>},
  ]
  function go(id:string){
    setActive(id)
    const sc = document.getElementById('jf-scroll')

    // Home → langsung ke atas
    if(id==='cover'){
      if(sc) sc.scrollTo({top:0,behavior:'smooth'})
      else window.scrollTo({top:0,behavior:'smooth'})
      return
    }

    const el = document.getElementById(id)
    if(!el) return

    if(sc){
      // Posisi elemen relatif terhadap scroll container
      const containerTop = sc.getBoundingClientRect().top
      const elTop = el.getBoundingClientRect().top
      const offset = elTop - containerTop + sc.scrollTop - 8
      sc.scrollTo({top: offset, behavior:'smooth'})
    } else {
      el.scrollIntoView({behavior:'smooth', block:'start'})
    }
  }
  return(
    <nav id='jf-nav'
      style={{position:'fixed',bottom:0,right:0,width:'100vw',zIndex:100,
        background:'#fff',borderTop:`1px solid rgba(168,80,112,0.13)`,
        boxShadow:'0 -3px 20px rgba(123,28,46,0.09)'}}>
      <div style={{display:'flex'}}>
        {items.map(it=>(
          <button key={it.id} onClick={()=>go(it.id)}
            style={{flex:1,display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',
              gap:2,padding:'10px 4px 8px',
              color:active===it.id?C.maroon:C.dusty,
              background:'none',border:'none',cursor:'pointer',
              position:'relative',WebkitTapHighlightColor:'transparent'}}>
            {active===it.id&&(
              <span style={{position:'absolute',top:0,left:'50%',transform:'translateX(-50%)',
                width:28,height:2.5,background:C.maroon,borderRadius:'0 0 3px 3px'}}/>
            )}
            <span style={{opacity:active===it.id?1:0.52,display:'flex',alignItems:'center'}}>{it.icon}</span>
            <span style={{fontFamily:"'Lato',sans-serif",fontSize:'0.46rem',letterSpacing:'0.07em',
              fontWeight:active===it.id?700:400,lineHeight:1}}>
              {it.label}
            </span>
          </button>
        ))}
      </div>
    </nav>
  )
}